import { createContext, createElement, useContext, useRef } from 'react'
import type { FunctionComponent, ReactElement, ReactNode } from 'react'
import { createStore, getDefaultStore } from '../vanilla.ts'

type Store = ReturnType<typeof createStore>

type StoreContextType = ReturnType<typeof createContext<Store | undefined>>
const StoreContext: StoreContextType = createContext<Store | undefined>(
  undefined,
)

type Options = {
  store?: Store
}

export function useStore(options?: Options): Store {
  const store = useContext(StoreContext)
  return options?.store || store || getDefaultStore()
}

export function Provider({
  children,
  store,
}: {
  children?: ReactNode
  store?: Store
}): ReactElement<
  { value: Store | undefined },
  FunctionComponent<{ value: Store }>
> {
  const storeRef = useRef<Store>(null)
  if (store) {
    return createElement(StoreContext.Provider, { value: store }, children)
  }
  if (storeRef.current === null) {
    storeRef.current = createStore()
  }
  return createElement(
    StoreContext.Provider,
    {
      // TODO: If this is not a false positive, consider using useState instead of useRef like https://github.com/pmndrs/jotai/pull/2771
      // eslint-disable-next-line react-hooks/refs
      value: storeRef.current,
    },
    children,
  )
}

import * as ActionTypes from '../actions'
import merge from 'lodash/merge'
import paginate from './paginate'
import { combineReducers } from 'redux'

// Updates an entity cache in response to any action with response.entities.
const entities = (state = { users: {}, repos: {} }, action) => {
  if (action.response && action.response.entities) {
    return merge({}, state, action.response.entities)
  }

  return state
}

// Updates error message to notify about the failed fetches.
const errorMessage = (state = null, action) => {
  const { type, error } = action

  if (type === ActionTypes.RESET_ERROR_MESSAGE) {
    return null
  } else if (error) {
    return error
  }

  return state
}

// Updates the pagination data for different actions.
const pagination = combineReducers({
  starredByUser: paginate({
    mapActionToKey: action => action.login,
    types: [
      ActionTypes.STARRED_REQUEST,
      ActionTypes.STARRED_SUCCESS,
      ActionTypes.STARRED_FAILURE
    ]
  }),
  stargazersByRepo: paginate({
    mapActionToKey: action => action.fullName,
    types: [
      ActionTypes.STARGAZERS_REQUEST,
      ActionTypes.STARGAZERS_SUCCESS,
      ActionTypes.STARGAZERS_FAILURE
    ]
  })
})

const rootReducer = combineReducers({
  entities,
  pagination,
  errorMessage
})

export default rootReducer

const trigger = useCallback(
  async (arg: any, opts?: SWRMutationConfiguration<Data, Error>) => {
    const [serializedKey, resolvedKey] = serialize(keyRef.current)

    if (!fetcherRef.current) {
      throw new Error('Can\'t trigger the mutation: missing fetcher.')
    }
    if (!serializedKey) {
      throw new Error('Can\'t trigger the mutation: missing key.')
    }

    const options = mergeObjects(
      mergeObjects(
        { populateCache: false, throwOnError: true },
        configRef.current
      ),
      opts
    )

    const mutationStartedAt = getTimestamp()
    ditchMutationsUntilRef.current = mutationStartedAt
    setState({ isMutating: true })

    try {
      const data = await mutate<Data>(
        serializedKey,
        (fetcherRef.current as any)(resolvedKey, { arg }),
        mergeObjects(options, { throwOnError: true })
      )

      if (ditchMutationsUntilRef.current <= mutationStartedAt) {
        startTransition(() =>
          setState({ data, isMutating: false, error: undefined })
        )
        options.onSuccess?.(data as Data, serializedKey, options)
      }
      return data
    } catch (error) {
      if (ditchMutationsUntilRef.current <= mutationStartedAt) {
        startTransition(() =>
          setState({ error: error as Error, isMutating: false })
        )
        options.onError?.(error as Error, serializedKey, options)
        if (options.throwOnError) {
          throw error as Error
        }
      }
    }
  },
  []
)

import { useForceUpdate } from "@ariakit/react-utils";
import { getDocument } from "@ariakit/utils";
import { useCallback, useEffect } from "react";
import { flushSync } from "react-dom";

interface Props {
  attribute: string;
  contentId?: string;
  contentElement?: HTMLElement | null;
  enabled?: boolean;
}

export function useRootDialog({
  attribute,
  contentId,
  contentElement,
  enabled,
}: Props) {
  const [updated, retry] = useForceUpdate();

  const isRootDialog = useCallback(() => {
    if (!enabled) return false;
    if (!contentElement) return false;
    const { body } = getDocument(contentElement);
    const id = body.getAttribute(attribute);
    return !id || id === contentId;
    // oxlint-disable-next-line exhaustive-deps
  }, [updated, enabled, contentElement, attribute, contentId]);

  useEffect(() => {
    if (!enabled) return;
    if (!contentId) return;
    if (!contentElement) return;
    const { body } = getDocument(contentElement);
    if (isRootDialog()) {
      body.setAttribute(attribute, contentId);
      return () => body.removeAttribute(attribute);
    }
    // If the dialog is not the root, there may be another dialog that will be
    // closed soon, which will remove the root attribute from the body. We
    // observe this change and retry to see if this dialog is now the root.
    const observer = new MutationObserver(() => flushSync(retry));
    observer.observe(body, { attributeFilter: [attribute] });
    return () => observer.disconnect();
    // oxlint-disable-next-line exhaustive-deps
  }, [updated, enabled, contentId, contentElement, isRootDialog, attribute]);

  return isRootDialog;
}

import { hasProp, isFunction } from '@zag-js/utils'
import { createContext as createReactContext, useContext as useReactContext } from 'react'

interface CreateContextOptions<T> {
  strict?: boolean | undefined
  hookName?: string | undefined
  providerName?: string | undefined
  errorMessage?: string | undefined
  name?: string | undefined
  defaultValue?: T | undefined
}

type CreateContextReturn<T> = [React.Provider<T>, () => T, React.Context<T>]

function getErrorMessage(hook: string, provider: string) {
  return `${hook} returned \`undefined\`. Seems you forgot to wrap component within ${provider}`
}

export function createContext<T>(options: CreateContextOptions<T> = {}) {
  const {
    name,
    strict = true,
    hookName = 'useContext',
    providerName = 'Provider',
    errorMessage,
    defaultValue,
  } = options

  const Context = createReactContext<T | undefined>(defaultValue)

  Context.displayName = name

  function useContext() {
    const context = useReactContext(Context)

    if (!context && strict) {
      const error = new Error(errorMessage ?? getErrorMessage(hookName, providerName))
      error.name = 'ContextError'
      if (hasProp(Error, 'captureStackTrace') && isFunction(Error.captureStackTrace)) {
        Error.captureStackTrace(error, useContext)
      }
      throw error
    }

    return context
  }

  return [Context.Provider, useContext, Context] as CreateContextReturn<T>
}

import React, { useEffect, useRef, useState } from 'react';
import { flushSync } from 'react-dom';

interface ResizeObserverDimensions {
  width: number;
  height: number;
  contentWidth: number;
  contentHeight: number;
}
export function useDimensions<T extends HTMLElement | null>(
  elementRef: React.RefObject<T>
): ResizeObserverDimensions | null {
  const resizeObserverRef = useRef<ResizeObserver | null>(null);
  const [dimensions, setDimensions] = useState<ResizeObserverDimensions | null>(null);

  useEffect(() => {
    if (!elementRef.current) {
      return;
    }

    resizeObserverRef.current = new ResizeObserver((entries) => {
      if (entries[0]) {
        const entry = entries[0];
        const updateDimensions = () => {
          setDimensions({
            width: entry.borderBoxSize[0]?.inlineSize ?? entry.target.clientWidth,
            height: entry.borderBoxSize[0]?.blockSize ?? entry.target.clientHeight,
            contentWidth: entry.contentRect.width,
            contentHeight: entry.contentRect.height,
          });
        };

        flushSync(updateDimensions);
      }
    });

    resizeObserverRef.current.observe(elementRef.current);

    return () => {
      if (resizeObserverRef.current) {
        resizeObserverRef.current.disconnect();
        resizeObserverRef.current = null;
      }
    };
  }, [elementRef.current]);

  return dimensions;
}

