export const useLocalizationContext = () => {
  const localization = React.useContext(PickerAdapterContext);
  if (localization === null) {
    throw new Error(
      `MUI X: Can not find the date and time pickers localization context.
It looks like you forgot to wrap your component in LocalizationProvider.
This can also happen if you are bundling multiple versions of the \`@mui/x-date-pickers\` package`,
    );
  }

  if (localization.adapter === null) {
    throw new Error(
      `MUI X: Can not find the date and time pickers adapter from its localization context.
It looks like you forgot to pass a \`dateAdapter\` to your LocalizationProvider.`,
    );
  }

  const localeText = React.useMemo(
    () => ({ ...DEFAULT_LOCALE, ...localization.localeText }),
    [localization.localeText],
  );

  return React.useMemo(
    () =>
      ({
        ...localization,
        localeText,
      }) as UseLocalizationContextReturnValue,
    [localization, localeText],
  );
};

export interface UseLocalizationContextReturnValue extends Omit<
  PickersAdapterContextValue,
  'localeText'
> {
  localeText: PickersLocaleText;
}

export const usePickerAdapter = () => useLocalizationContext().adapter;

const updateValidAndValue = (
  name: InternalFieldName,
  shouldSkipSetValueAs: boolean,
  value?: unknown,
  ref?: Ref,
) => {
  const field: Field = get(_fields, name);

  if (field) {
    if (hasExplicitNullIntermediate(name)) {
      return;
    }

    const wasUnsetInFormValues = isUndefined(get(_formValues, name));
    const defaultValue = get(
      _formValues,
      name,
      isUndefined(value) ? get(_defaultValues, name) : value,
    );

    isUndefined(defaultValue) ||
    (ref && (ref as HTMLInputElement).defaultChecked) ||
    shouldSkipSetValueAs
      ? set(
          _formValues,
          name,
          shouldSkipSetValueAs ? defaultValue : getFieldValue(field._f),
        )
      : setFieldValue(name, defaultValue);

    if (_state.mount && !_state.action) {
      _setValid();

      // Re-registering a field after a prior unregister puts its key back
      // into _formValues, which can flip isDirty back to false (#13397).
      // Only run when we are currently dirty, otherwise an initial register
      // for a field with no defaultValue would flip isDirty to true. Reset
      // paths repopulate _formValues before re-register, so the key is
      // present then and this branch is skipped (preserves keepDirty).
      if (
        wasUnsetInFormValues &&
        _formState.isDirty &&
        (_proxyFormState.isDirty || _proxySubscribeFormState.isDirty)
      ) {
        const isDirty = _getDirty();
        if (!isDirty) {
          _formState.isDirty = false;
          _subjects.state.next({ ..._formState });
        }
      }
    }
  }
};

