'use client';

import useEventCallback from '@mui/utils/useEventCallback';
import { type ChartPlugin } from '../../models';
import {
  type UseChartSeriesConfigSignature,
  type SerializeIdentifierFunction,
  type CleanIdentifierFunction,
} from './useChartSeriesConfig.types';
import { serializeIdentifier as serializeIdentifierFn } from './utils/serializeIdentifier';
import { cleanIdentifier as cleanIdentifierFn } from './utils/cleanIdentifier';
import type { ChartSeriesConfig } from './types';

export const useChartSeriesConfig: ChartPlugin<UseChartSeriesConfigSignature> = ({ store }) => {
  const serializeIdentifier: SerializeIdentifierFunction = useEventCallback((identifier) =>
    serializeIdentifierFn(store.state.seriesConfig.config, identifier),
  );

  const cleanIdentifier: CleanIdentifierFunction = useEventCallback(function cleanIdentifier(
    identifier: Parameters<CleanIdentifierFunction>[0],
  ) {
    return cleanIdentifierFn(store.state.seriesConfig.config, identifier);
  });

  return {
    instance: {
      serializeIdentifier,
      cleanIdentifier,
    },
  };
};

useChartSeriesConfig.params = {
  seriesConfig: true,
};

useChartSeriesConfig.getDefaultizedParams = ({ params }) => ({
  ...params,
  seriesConfig: params.seriesConfig ?? ({} as ChartSeriesConfig<any>),
});

useChartSeriesConfig.getInitialState = ({ seriesConfig }) => {
  return {
    seriesConfig: {
      config: seriesConfig,
    },
  };
};

import type {
  GridColDef,
  GridSingleSelectColDef,
  GridMultiSelectColDef,
} from '../../../models/colDef/gridColDef';
import type { GridValueOptionsParams } from '../../../models/params/gridValueOptionsParams';

export function isSingleSelectColDef(colDef: GridColDef | null): colDef is GridSingleSelectColDef {
  return colDef?.type === 'singleSelect';
}

export function isMultiSelectColDef(colDef: GridColDef | null): colDef is GridMultiSelectColDef {
  return colDef?.type === 'multiSelect';
}

export function getValueOptions(
  column: GridSingleSelectColDef | GridMultiSelectColDef,
  additionalParams?: Omit<GridValueOptionsParams, 'field'>,
) {
  if (!column) {
    return undefined;
  }
  return typeof column.valueOptions === 'function'
    ? column.valueOptions({ field: column.field, ...additionalParams })
    : column.valueOptions;
}

export function getValueFromValueOptions(
  value: string,
  valueOptions: any[] | undefined,
  getOptionValue: NonNullable<GridSingleSelectColDef['getOptionValue']>,
) {
  if (valueOptions === undefined) {
    return undefined;
  }
  const result = valueOptions.find((option) => {
    const optionValue = getOptionValue(option);
    return String(optionValue) === String(value);
  });
  return getOptionValue(result);
}

import { createRootSelector, createSelector } from '../../../utils/createSelector';
import type { GridStateCommunity } from '../../../models/gridStateCommunity';
import type { GridRowId } from '../../../models/gridRows';

export const gridRowReorderStateSelector = createRootSelector(
  (state: GridStateCommunity) => state.rowReorder,
);

export const gridIsRowDragActiveSelector = createSelector(
  gridRowReorderStateSelector,
  (rowReorder) => rowReorder?.isActive ?? false,
);

// Selector for the entire drop target state
export const gridRowDropTargetSelector = createSelector(
  gridRowReorderStateSelector,
  (rowReorder) => rowReorder?.dropTarget ?? { rowId: null, position: null },
);

export const gridRowDropTargetRowIdSelector = createSelector(
  gridRowDropTargetSelector,
  (dropTarget) => dropTarget.rowId ?? null,
);

// Selector for a specific row's drop position
export const gridRowDropPositionSelector = createSelector(
  gridRowDropTargetSelector,
  (dropTarget, rowId: GridRowId) => {
    if (dropTarget.rowId === rowId) {
      return dropTarget.position;
    }
    return null;
  },
);

// Selector for the dragged row ID
export const gridDraggedRowIdSelector = createSelector(
  gridRowReorderStateSelector,
  (rowReorder) => rowReorder?.draggedRowId ?? null,
);
